Here's a robust C++ program to count word occurrences in a text file, designed for efficiency and clarity:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <unordered_map>

using namespace std;

int countWordOccurrences(const string& filename, const string& targetWord) {
    unordered_map<string, int> wordCounts; // Using unordered_map for efficient lookup
    ifstream file(filename);

    if (!file.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return -1; // Indicate an error
    }

    string line;
    while (getline(file, line)) {
        stringstream ss(line);
        string currentWord;

        while (ss >> currentWord) {
            // Normalize word for case-insensitive comparison (optional but recommended)
            transform(currentWord.begin(), currentWord.end(), currentWord.begin(), ::tolower);

            if (currentWord == targetWord) {
                wordCounts[targetWord]++;
            } 
        } 
    }

    file.close();
    return wordCounts[targetWord]; // Return the count for the specific word
}

int main() {
    string filename = "my_text_file.txt"; 
    string targetWord = "example";

    int occurrences = countWordOccurrences(filename, targetWord);

    if (occurrences >= 0) { 
        cout << "Occurrences of '" << targetWord << "' in '" << filename << "': " << occurrences << endl;
    }

    return 0;
}
```

